function ui(){let map={sub:'sub',heroBadge:'badge',hero:'hero',heroP:'p',start:'start',practice:'practice',progressLabel:'progress',officialLabel:'official',njLabel:'nj',examLabel:'oral',route:'route',studyTitle:'study',answerLabel:'answer',memoryLabel:'memory',simLabel:'sim',examTitle:'exam',examHelp:'examHelp',officialMode:'officialMode',allMode:'allMode',njMode:'njMode',cardsTitle:'cardsTitle',cardsHelp:'cardsHelp',mistTitle:'mist',clearMist:'clear',navStudy:'navStudy',navExam:'navExam',navCards:'navCards',navMist:'navMist',notice:'notice'};Object.entries(map).forEach(([id,k])=>$('#'+id).textContent=tx(k));$('#search').placeholder=tx('search');$('#lang').textContent=lang==='en'?'ES':'EN';buildFilter();renderList();renderStudy();renderCard();renderMist();if(deck.length)showExam(false)}
function buildFilter(){let cats=[...new Set(D.questions.map(q=>q.cat))];let current=$('#filter').value||filter;$('#filter').innerHTML=`<option value="all">${tx('allCats')}</option>`+cats.map(c=>`<option value="${c}">${c}</option>`).join('');$('#filter').value=current;}
function visible(){let s=$('#search').value.toLowerCase();return D.questions.filter(q=>(filter==='all'||q.cat===filter)&&(q.q[lang].toLowerCase().includes(s)||q.a[lang].toLowerCase().includes(s)))}
function renderList(){let arr=visible();$('#list').innerHTML='';arr.forEach(q=>{let i=D.questions.indexOf(q),b=document.createElement('button');b.className='card w-full rounded-2xl border border-transparent p-4 text-left '+(i===idx?'active':'');b.innerHTML=`<div class="flex gap-3"><span class="grid h-9 w-9 place-items-center rounded-full ${q.official?'bg-blue-100 text-blue-800':'bg-red-100 text-red-800'} font-black">${q.n}</span><div class="flex-1"><small class="font-bold text-slate-500">${q.cat}</small><b class="block">${q.q[lang]}</b></div><span>${learned.includes(q.n)?'✅':''}</span></div>`;b.onclick=()=>{idx=i;renderList();renderStudy()};$('#list').appendChild(b)})}
function progress(){let p=Math.round(learned.length/D.questions.length*100);$('#pct').textContent=p+'%';$('#progressCount').textContent=learned.length+' / '+D.questions.length;$('#bar').style.width=p+'%'}
function renderStudy(){let q=D.questions[idx];$('#number').textContent=(q.official?tx('official'):tx('nj'))+' #'+q.n;$('#question').textContent=q.q[lang];$('#answer').textContent=q.a[lang];$('#fact').textContent=q.fact[lang];$('#learned').textContent=learned.includes(q.n)?tx('done'):tx('mark');progress()}
$('#learned').onclick=()=>{let n=D.questions[idx].n;learned=learned.includes(n)?learned.filter(x=>x!==n):[...learned,n];localStorage.citLearned=JSON.stringify(learned);renderList();renderStudy()};$('#prev').onclick=()=>{idx=Math.max(0,idx-1);renderList();renderStudy()};$('#next').onclick=()=>{idx=Math.min(D.questions.length-1,idx+1);renderList();renderStudy()};$('#search').oninput=renderList;$('#filter').onchange=e=>{filter=e.target.value;renderList()};
function view(v){$$('.view').forEach(x=>x.classList.remove('active'));$('#'+v).classList.add('active');if(v==='exam'&&!deck.length)startExam(mode);if(v==='mistakes')renderMist();scrollTo(0,0)}$$('.nav').forEach(b=>b.onclick=()=>view(b.dataset.v));
function markMode(){$$('.mode').forEach(b=>b.className='mode rounded-xl border px-4 py-3 font-bold');document.querySelector(`[data-mode="${mode}"]`).className='mode rounded-xl bg-blue-700 px-4 py-3 font-bold text-white'}$$('.mode').forEach(b=>b.onclick=()=>{mode=b.dataset.mode;markMode();startExam(mode)});
function startExam(m){mode=m;markMode();let p=m==='official'?D.questions.filter(q=>q.official).sort(()=>Math.random()-.5).slice(0,20):m==='nj'?D.questions.filter(q=>!q.official):[...D.questions];deck=p;ei=0;score=0;answered=false;showExam(true)}
function showExam(reset=true){if(mode==='official'&&(score>=12||(ei-score)>=9))return result();if(ei>=deck.length)return result();answered=false;let q=deck[ei];$('#examCount').textContent=(ei+1)+' / '+deck.length;$('#examScore').textContent=tx('score')+': '+score;$('#examBar').style.width=(ei/deck.length*100)+'%';$('#examBox').innerHTML=`<p class="text-sm font-bold text-blue-700">${q.cat}</p><h3 class="mt-2 text-3xl font-black leading-tight">${q.q[lang]}</h3><button id="showAns" class="mt-7 rounded-xl bg-blue-700 px-5 py-3 font-black text-white">${tx('show')}</button><div id="revealed"></div>`;$('#showAns').onclick=()=>{$('#revealed').innerHTML=`<div class="mt-6 rounded-2xl bg-emerald-50 p-6"><b>${tx('answer')}</b><p class="mt-2 text-2xl font-black">${q.a[lang]}</p><p class="mt-3">${q.fact[lang]}</p></div><div class="mt-5 flex flex-wrap gap-3"><button id="yes" class="rounded-xl bg-emerald-600 px-5 py-3 font-black text-white">${tx('know')}</button><button id="no" class="rounded-xl bg-red-600 px-5 py-3 font-black text-white">${tx('miss')}</button></div>`;$('#showAns').remove();$('#yes').onclick=()=>grade(true,q);$('#no').onclick=()=>grade(false,q)}}
function grade(ok,q){if(answered)return;answered=true;if(ok)score++;else{if(!mist.some(x=>x.n===q.n))mist.unshift(q);localStorage.citMist=JSON.stringify(mist)}ei++;showExam(true)}
function result(){let wrong=ei-score,passed=mode==='official'?score>=12:score/Math.max(1,ei)>=.6;$('#examCount').textContent=score+' / '+ei;$('#examScore').textContent=tx('score')+': '+score;$('#examBar').style.width='100%';$('#examBox').innerHTML=`<div class="py-10 text-center"><div class="text-7xl">${passed?'🏆':'📚'}</div><h3 class="mt-5 text-3xl font-black">${passed?tx('passed'):tx('failed')}</h3><p class="mt-3 text-lg">${score} ${tx('correct').replace('✅ ','')} • ${wrong} ${tx('wrong').replace('❌ ','')}</p><button id="again" class="mt-7 rounded-xl bg-blue-700 px-6 py-3 font-black text-white">${tx('again')}</button></div>`;$('#again').onclick=()=>startExam(mode)}
function renderCard(){let q=D.questions[card];$('#flashLabel').textContent=flipped?tx('back'):tx('front')+' '+(card+1)+' / '+D.questions.length;$('#flashText').innerHTML=flipped?`${q.a[lang]}<span class="mt-6 block text-base font-normal leading-7 text-blue-100">${q.fact[lang]}</span>`:q.q[lang]}$('#flash').onclick=()=>{flipped=!flipped;renderCard()};$('#cardPrev').onclick=()=>{card=(card-1+D.questions.length)%D.questions.length;flipped=false;renderCard()};$('#cardNext').onclick=()=>{card=(card+1)%D.questions.length;flipped=false;renderCard()};
function renderMist(){$('#mistList').innerHTML=mist.length?mist.map(q=>`<div class="rounded-2xl border bg-white p-5"><b>${q.q[lang]}</b><p class="mt-2 text-xl font-black text-emerald-700">${q.a[lang]}</p><p class="mt-2 text-slate-600">${q.fact[lang]}</p></div>`).join(''):`<div class="rounded-2xl bg-white p-8 text-center">${tx('empty')}</div>`}$('#clearMist').onclick=()=>{mist=[];localStorage.citMist='[]';renderMist()};
$('#lang').onclick=()=>{lang=lang==='en'?'es':'en';localStorage.citLang=lang;ui()};ui();